export function usePartnerDashboardApi() {
    const { $api } = useNuxtApp()
    return {
        getMyProfile() { return $api<any>('/partners/me') },
        updateProfile(data: any) { return $api<any>('/partners/me', { method: 'PUT', body: data }) },
        getMyStats() { return $api<any>('/partners/me/stats') },
        getMyCommissions(params?: any) { return $api<any>('/commissions/me', { params }) },
        getMyWallet() { return $api<any>('/wallets/me') },
        requestWithdrawal(data: { amount: number; bankDetails: any }) { return $api<any>('/wallets/withdraw', { method: 'POST', body: data }) },
        getMyWithdrawals(params?: any) { return $api<any>('/wallets/withdrawals/me', { params }) },
        getMyReferrals(params?: any) { return $api<any>('/partners/me/referrals', { params }) },
        getMyNetwork(params?: any) { return $api<any>('/partners/me/network', { params }) },
    }
}
